import{_ as n,I as b,o as p,c as a,a4 as r,j as i,a as l,J as s,w as t}from"./chunks/framework.EYT3XhWU.js";const C=JSON.parse('{"title":"转折关系","description":"","frontmatter":{},"headers":[],"relativePath":"行测/言语理解/中心理解/转折关系.md","filePath":"行测/言语理解/中心理解/转折关系.md"}'),x={name:"行测/言语理解/中心理解/转折关系.md"},d={class:"details custom-block",open:"",style:{"box-sizing":"border-box",border:"1px solid rgba(0, 0, 0, 0)","border-radius":"8px",padding:"16px 16px 8px","line-height":"24px","font-size":"16px",color:"rgb(223, 223, 214)","background-color":"rgba(142, 150, 170, 0.14)",margin:"0px !important"}},g={start:"6",style:{"box-sizing":"border-box","list-style":"decimal",margin:"16px 0px",padding:"0px 0px 0px 1.25rem"}},w={style:{"box-sizing":"border-box","overflow-wrap":"break-word","list-style":"none"}},y={class:"details custom-block",open:"",style:{"box-sizing":"border-box",border:"1px solid rgba(0, 0, 0, 0)","border-radius":"8px",padding:"16px 16px 8px","line-height":"24px","font-size":"16px",color:"rgb(223, 223, 214)","background-color":"rgba(142, 150, 170, 0.14)",margin:"0px !important"}},m={start:"5",style:{"box-sizing":"border-box","list-style":"decimal",margin:"16px 0px",padding:"0px 0px 0px 1.25rem"}},z={style:{"box-sizing":"border-box","overflow-wrap":"break-word","list-style":"none"}};function k(f,o,v,_,c,u){const e=b("font");return p(),a("div",null,[o[14]||(o[14]=r('<h1 id="转折关系" tabindex="-1">转折关系 <a class="header-anchor" href="#转折关系" aria-label="Permalink to “转折关系”">​</a></h1><p>字数: 5153 字 时长: 19 分钟 <strong>VIP文档</strong></p><ol><li>转折关系指前后句子在语义或情感倾向上形成对立或反转。例如，“他努力备考，却因生病未能参加考试”，后句通过“却”对前句的预期结果进行否定，体现逻辑上的矛盾性。</li></ol><h2 id="一、常用转折词" tabindex="-1">一、常用转折词 <a class="header-anchor" href="#一、常用转折词" aria-label="Permalink to “一、常用转折词”">​</a></h2><ol><li><p>1、常用格式</p><ol><li>● 强转折：虽然……但是……、尽管……还是……</li><li>● 弱转折：其实、事实上、只是、实际上、殊不知</li></ol></li><li><p>2、替换词语</p><p>：</p><ol><li>● 虽然：虽说、固、尽管如此；</li><li>● 但是：可是、不过、然而、却、但相反的、但另一方面</li></ol></li></ol><h2 id="二、解题技巧" tabindex="-1">二、解题技巧 <a class="header-anchor" href="#二、解题技巧" aria-label="Permalink to “二、解题技巧”">​</a></h2><ol><li><strong>1</strong>、大多数转折词后为文段重点，转折前的表述通常为错误的选项，文段如果出现“很多人/大多数人/传统观点/以前/有些人/不少人认为 + 转折关联词”的表述，一般直接看转折词之后的内容，并看哪个选项是转折之后内容的同义替换，即为正确答案。</li><li><strong>2</strong>、当文段出现弱转折时，有两种作用，如果跟前面的方向是相反的，那它表转折，如果是一致的，则是补充论证。</li><li><strong>3</strong>、转折关系的文段中，“虽然”可能会省略，会直接出现“但是”“然而”“却”，要学会判别这是转折关系。</li><li><strong>4</strong>、注意若最后一个转折出现在解释说明、举例论证等分述句中，则失效。</li></ol><h2 id="三、随笔练习" tabindex="-1">三、随笔练习 <a class="header-anchor" href="#三、随笔练习" aria-label="Permalink to “三、随笔练习”">​</a></h2><p><strong>例1</strong>：（2019山东选调）有人说 , 阻碍中国城市化进程的根本问题是农村教育的不发达 , 文化知识水平偏低的农民即便进入城市 , 也只能从事最简单的体力劳动 , 而城市化程度越高 , 对劳动力素质的要求也越高 , 最终农民中的大部分人依然要从城市退出。可是，农村教育的落后恰恰是政府的过失, 绝不能以此延缓户籍改革和城市化进程。</p><ol><li>这段文字旨在强调：</li><li>A. 农村教育的不发达阻碍了中国的城市化进程</li><li>B. 城市化程度与其对劳动力素质的要求成正比</li><li>C. 绝不能因农村教育落后而延缓城市化进程</li><li>D. 农村教育的落后与政府的过失有直接关系</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="7" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">文段首先通过“有人说”指出别人的观点，即农村教育阻碍了城市化进程，并分析原因，之后通过转折关联词“可是”引出作者观点，主旨句所在，“农村教育的落后恰恰是政府过失，绝不能以此延缓户籍改革和城市化进程。”C 选项是主旨的同义替换项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项，为开篇“有人说”的观点，在转折词“可是”之前，非重点，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项“正比”对应文段“城市化程度越高，对劳动力素质的要求也越高”，也为转折词“可是”之前的内容，非重点，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项，文段重点讨论城市化进程的问题，而非农村教育落后的原因，选项未提及文段重点内容“城市化进程”，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为C。</li></ol></details><p><strong>例2</strong>：（2018吉林长春某单位）互联网时代，地球是平的，这意味着在今天这样一个因信息技术而紧密、方便联系的互联网世界中，已经冲破了国家和地域的限制。然而，不同的国家和地域，拥有不同的文化和生活方式，用户的管理方式和本地诉求也不尽相同，谁能更好地满足用户需求，提升用户体验，谁就能在竞争中占据主动权，从而赢得一片广阔的市场。</p><ol><li>这段文字意在说明在互联网时代（ ）。</li><li>A. 满足不同的用户需求是竞争的关键</li><li>B. 世界因技术而紧密联系</li><li>C. 信息技术的飞跃是行业发展的重要契机</li><li>D. 互联网产品呈多样化发展趋势</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="7" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">文段开篇引出“信息已冲破了国家和地域的限制”的现实背景，接着通过“然而”转折关联词引出观点，即“谁能更好地满足用户需求，谁就能赢得市场”，观点部分为重点，对应A项；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项，对应转折之前的部分，非文段重点，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项，文段中并未提及“信息技术的飞跃是行业发展的重要契机”这一关系，无中生有，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项，文段重点是“用户需求”，而非“多样化发展趋势”，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为A。</li></ol></details><p><strong>例3</strong>：（2015国考）西方现代文论认为，一部作品产生后就是独立的文本，和作者无关。然而这个原则却不适用于中国传统文学。中国古代的文学家，很多是朝廷的官员或预备官员，至少是读书人，是文明的传承者，他们的言行是社会风尚的风向标，文学承载着移风易俗的责任，因此社会价值体系对文学家的人格有较高的要求。如汉代的扬雄写过赞美王莽的文章，因而被宋人看不起；严嵩的诗写得好，但是后世读的人少，诗集也少有刊刻——怎能让祸国殃民的罪人立言不朽呢！古人虽也说过“孔雀虽有毒，不能掩文章”的话，但仍坚持“德艺双馨”的文艺评论原则。</p><ol><li>根据这段文字，下列哪项符合传统上中国古代对文学作品的看法：</li><li>A.文如其人</li><li>B.文以载道</li><li>C.知人论世</li><li>D.诗以言志</li></ol>',16)),i("details",d,[i("ol",g,[i("li",w,[o[2]||(o[2]=l("根据题干，需对中国古代对文学作品的看法加以概括。文段首句先提出西方现代文论的观点是“作品与作者无关”。",-1)),s(e,{color:"#409EFF",style:{"box-sizing":"border-box"}},{default:t(()=>[...o[0]||(o[0]=[l("随后以“然而”为转折的标志",-1)])]),_:1}),o[3]||(o[3]=l("，提出西方的观点不适用于中国的传统文学，即中国与西方的观点是相反的。",-1)),o[4]||(o[4]=i("br",{style:{"box-sizing":"border-box"}},null,-1)),s(e,{color:"#409EFF",style:{"box-sizing":"border-box"}},{default:t(()=>[...o[1]||(o[1]=[l("转折前的观点是“作品与作者无关”。转折前后语义相反",-1)])]),_:1}),o[5]||(o[5]=l("，且文中明确提出此观点不适用于中国传统文学。故转折后的观点是作品与作者有关。",-1))]),o[6]||(o[6]=i("li",{style:{"box-sizing":"border-box","overflow-wrap":"break-word","list-style":"none","margin-top":"8px"}},"分析选项，只有A选项既包括作品(文)，又包括作者(人)。B、D两项仅有作品(文、诗)。并无作者；C选项仅有作者(人)，并无作品。",-1)),o[7]||(o[7]=i("li",{style:{"box-sizing":"border-box","overflow-wrap":"break-word","list-style":"none","margin-top":"8px"}},"故正确答案为A。",-1))])]),o[15]||(o[15]=r('<p><strong>例4</strong>：（2023国考）“高精尖”产业是辐射带动力强的产业集群，对经济具有极强的拉动作用，不仅能实现中心城市的经济高质量发展，而且能带动周边地区的产业联动转型。京津冀协同发展中，产业对接协作是区域战略的核心内容之一，产业升级是三地的共同任务，在疏解非首都核心功能的过程中，天津和河北是北京产业转移的主要承接者。然而，两地仅简单承接北京转移的一般产业是远远不够的，迫切需要发展“高精尖”产业，带动区域科技创新与成果转化，促进区域产业联动，形成经济协同发展的格局。</p><ol><li>这段文字意在说明：</li><li>A.“高精尖”产业承担着高水平创新的重大使命</li><li>B.形成“高精尖”产业是城市群建设的长远目标</li><li>C.我国区域经济发展应以“高精尖”产业为依托</li><li>D.“高精尖”产业对京津冀协同发展有重要意义</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">文段开篇引出话题“高精尖”产业，并指出其对经济的拉动作用，能够带动周边地区的产业联动转型。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">接着介绍了京津冀协同发展中的区域战略和任务，并指出天津和河北是北京产业转移的主要承接者。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">尾句通过关联词“然而”<mark style="box-sizing:border-box;">转折</mark>，指出两地仅简单承接北京转移的一般产业是远远不够的，接着通过“迫切需要”引出对策，强调要发展“高精尖”产业，以实现京津冀地区的协同发展。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故文段重点强调转折后的对策，即发展“高精尖”产业对实现京津冀地区协同发展的重要性，对应D项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项，强调“高精尖”产业对高水平创新的重要性，缺少文段核心话题“京津冀协同发展”，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项，“城市群建设的长远目标”文段并未提及，无中生有，且“城市群建设”范围扩大，文段重点讨论“京津冀”地区，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项，强调我国应如何发展区域经济，文段讨论的话题是如何实现“京津冀”地区的协同发展，表述不够准确，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为D。</li></ol></details><p><strong>例5</strong>：（2022江苏）村居法律顾问作为农村和城市社区基层法律服务市场的服务主体，过去主要由基层法律工作者担任。基层法律工作者扎根基层服务基层，在基层法律服务领域作出巨大贡献。但随着现代基层社会治理法治化的快速发展和法律服务需求的不断增长变化，基层人民群众对法律服务产品和质量提出了更高的需求，传统的基层法律工作者职业队伍和服务模式都显现出一定的不适应和供给不足，亟待从根本上回应和回归法律服务市场的特殊规律，引入律师和律师团队是一种必然趋势。</p><ol><li>这段文字意在强调：</li><li>A.应重视基层法律工作者队伍的建设</li><li>B.实现基层治理法治化需要律师参与</li><li>C.村居法律顾问工作必须要与时俱进</li><li>D.基层法律工作者需要提升服务能力</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">文段开篇介绍村居法律顾问过去主要由基层法律工作者担任，他们在基层法律服务领域作出了巨大贡献。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">接着通过<mark style="box-sizing:border-box;">转折词</mark>“但”提出问题，即随着现代基层社会治理法治化的发展和法律服务需求的变化，传统基层法律工作者职业队伍和服务模式都显现出一定的不适应和供给不足，最后通过“必然趋势”提出对策，即要引入律师和律师团队，对策即为文段重点，对应B项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A、D两项，均没有提到“律师”这一核心话题，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项，“与时俱进”表述不明确，文段强调的是要引入律师和律师团队，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为B。</li></ol></details><p><strong>例6</strong>：（2022云南）科学家抱着极大的期望，发射了许多太空望远镜，如哈勃望远镜、开普勒望远镜等。经过这几十年的努力，科学家用望远镜在银河系里找到了700到800个比较像地球的行星。那上面是不是有外星人呢？这虽然引起了科学家极大的兴趣，但是很遗憾，由于距离太遥远了，无法进行探测。比如开普勒望远镜找到了一个地球的表兄弟——开普勒186f。它离地球有500光年，这意味着我们用望远镜看到的形貌，是它500年前的情况，光从它那儿传到地球要经过500年的时间。</p><ol><li>这段文字意在说明：</li><li>A.科学家发射了很多太空望远镜</li><li>B.开普勒186f离地球有500光年</li><li>C.外星人的发现受限于探测距离</li><li>D.银河系里存在很多类地行星</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">文段先介绍了近几十年太空望远镜的发射情况，并引出是否存在外星人的话题，随后通过<mark style="box-sizing:border-box;">转折</mark>指出“由于距离太遥远了，无法进行探测”，接下来举“开普勒望远镜”的例子解释说明，体现出较远的距离给太空探测带来了困难，故文段转折之后为重点，强调距离限制了太空探测，进而限制了外星人的发现，对应C项。</li></ol></details><p><strong>例7</strong>：（2022四川）一部医疗美容行业发展史，恰恰就是一部行业合规进化史。每次政策法规发布、重大行业执法活动，都会给行业合规带来短期震荡。但从行业中长期发展和结果来看，规范一定是行业发展的长期利好，不仅避免了合规企业被劣币驱逐，还能促进行业竞争力的提升。</p><ol><li>这段文字意在说明：</li><li>A.医疗美容行业走向整体规范化是必然要求</li><li>B.缺乏监管会导致合规医疗美容企业被排挤</li><li>C.医疗美容行业的合规有助于扩大市场占有率</li><li>D.医疗美容行业合规应建立在健全政策法规上</li></ol>',11)),i("details",y,[i("ol",m,[i("li",z,[o[9]||(o[9]=l("文段首先介绍医疗美容行业发展与行业合规之间的关系，接着指出政策法规发布等会给行业合规带来短期震荡，之后通过",-1)),o[10]||(o[10]=i("mark",{style:{"box-sizing":"border-box"}},"转折关联词",-1)),o[11]||(o[11]=l("“但”强调",-1)),s(e,{color:"#fc5531",style:{"box-sizing":"border-box"}},{default:t(()=>[...o[8]||(o[8]=[l("规范对医疗美容行业中长期发展利好",-1)])]),_:1}),o[12]||(o[12]=l("，后文“不仅······还能······”具体介绍了规范对医疗美容行业发展的重要意义。",-1))]),o[13]||(o[13]=r('<li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">由此可知，文段重在强调医疗美容行业的中长期发展离不开规范，对应A项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项，为问题表述，非重点，且文段并未涉及“缺乏监管”，无中生有，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项，“有助于······”为意义表述，非重点，且文段并未涉及“扩大市场占有率”，无中生有，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项，文段强调的是“规范”对医疗美容行业中长期发展的重要性，而非“健全政策法规”的重要性，偏离文段核心话题，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为A。</li>',5))])]),o[16]||(o[16]=r('<p><strong>例8</strong>：（2022天津）慈善是一个历史变动中的概念，所含内容在不同历史时期并不完全一致。譬如古代慈善事业多系直接性物质救济，呈现出重养轻教的特征。但近代以来，愈发重视慈善教育的功能，强调教养并重。当代中国慈善事业更是朝着社会公益服务的多元化方向发展。但是，不管如何变化，慈善的根本内涵没有改变，即民间社会各界秉持人道善心，救助、关怀社会弱势群体与困难群众，这也是慈善本义内容所在。至于慈善的外延表现，则会随着时代的变化而变化，譬如慈善动机、慈善形式、慈善流程等。我们在讨论慈善概念的时候，应该对其内涵与外延予以区分，在此基础上考察慈善发展的历史。</p><ol><li>这段文字意在说明：</li><li>A.公益服务慈善的核心要义</li><li>B.教养并重是当代慈善的主要特点</li><li>C.慈善的社会教育功能越来越受到重视</li><li>D.慈善的内涵并不随外延的变化而变化</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">文段首先引出“慈善”的话题，表明慈善在不同历史时期概念并不完全一致，接着通过“譬如”举例论证。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">然后通过转折关联词“但是”强调慈善的内涵没有改变。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">后文通过慈善的外延会随着时代的变化而变化，且在探讨慈善概念时，应对内涵与外延予以区分，来进一步论证慈善的内涵不会随着变化而变化。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故文段强调慈善内涵没有改变，对应D项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项，“公益服务”对应转折之前的内容，非重点，且“核心要义”表述不明确，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项“教养并重”及C项“慈善的社会教育功能”均为文段例子部分的内容，非重点，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为D。</li></ol></details><p><strong>例9</strong>：（2023甘肃）喝酒有害健康早已成为共识，酒精对大脑的影响也逐渐受到更多关注。《自然·通讯》的一项研究发现，每周喝几瓶啤酒，就会造成大脑灰质和白质体积减小；发表于《英国医学杂志》的一项研究指出，每周饮酒会导致海马体萎缩风险急剧上升。由此造成的后果是，长期饮酒的人更易患上痴呆症。不过，这些研究往往关注长期饮酒的影响，如果只是偶尔喝一次酒，也会对大脑造成危害吗？发表于《美国科学院院刊》的最新研究给出了肯定答案：你人生中的第一次醉酒，不仅会改变大脑神经元的形态，这种影响甚至会伴随终生。</p><ol><li>这段文字意在说明：</li><li>A.强调长期饮酒对健康的严重危害</li><li>B.纠正人们对饮酒危害的错误认识</li><li>C.探讨痴呆症与饮食习惯之间的关联</li><li>D.介绍关于饮酒危害健康的研究结论</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">文段首先引出“喝酒有害健康”这一话题，并通过列举两项研究对前面观点进行支撑论证，接着通过转折标志词“不过”引出问题，即偶尔喝酒会不会对大脑造成危害，随后由最新研究得出肯定答案，表示第一次醉酒便会对大脑带来危害。故文段通过转折重在强调目前研究的最新结论，即只要饮酒就会影响自己的身体健康，对应D项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项“长期饮酒”、C项“痴呆症”均对应转折前的内容，非重点，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项，文段重点强调饮酒会对人体带来伤害，并未对之前的观点进行反驳纠正，“纠正······错误认识”无中生有，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为D。</li></ol></details><p><strong>例10</strong>：（2022云南）除了探矿队员，很多矿石收藏家也对铀矿石感兴趣，因为它们实在太漂亮了。然而学过物理、化学的人都知道，不管化学上结合成什么物质，铀元素的放射性都是不会变的。那么把含铀的“毒花”放在博物馆甚至家里，真的没事吗？实际上，只要隔着一层玻璃，这些铀矿石就算放在卧室里都伤不了人，因为它们所含的铀，几乎全是放射性较弱的铀-238（俗称“贫铀”），只有极少量是用于制造核弹头的同位素铀-235。不过千万不要吸入它的粉尘，因为哪怕它所放出的最弱的α射线，也会造成辐射伤害。</p><ol><li>这段文字意在说明：</li><li>A.铀矿石为什么应该保存在玻璃柜中</li><li>B.铀矿石作为矿石收藏是比较安全的</li><li>C.铀-238与同位素铀-235有本质不同</li><li>D.粉尘态铀矿石的放射性会大大增强</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">文段开篇通过解释矿石收藏家对铀矿石感兴趣的原因引出“铀矿石”这一话题，随后通过转折词“然而”提出问题，即铀矿石放在博物馆甚至家里是否安全，紧接着由转折词“实际上”针对前文的问题进行回答，即只要防护得当，铀矿石收藏是安全的，后文通过“因为”对这一观点进行解释，故整个文段重点强调收藏铀矿石是比较安全的，对应B项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项，文段重点强调铀矿石收藏是安全的，保存在玻璃柜中并非单指收藏，与文段重点不符，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项，“铀-238与同位素铀-235”属于解释说明的内容，非重点，且未提及文段主题词“铀矿石”，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项，“粉尘态铀矿石”主题词范围缩小，文段主题词为“铀矿石”，且“放射性会大大增强”表述错误，文段指出“铀元素的放射性都是不会变的”，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为B。</li></ol></details>',9))])}const D=n(x,[["render",k]]);export{C as __pageData,D as default};
